from math import isqrt
def A360303(n):
    c, j, n2 = 0, 1, isqrt(n)
    while j <= n2:
        k = n//j
        m = n//k
        c += ((1<<m-j+1)-1)<<k-m
        j = m+1
    return c # _Chai Wah Wu_, May 19 2026

